INSERT INTO questions (question_text, choices, correct_answer, explanation, subject, topic, difficulty, exam_type) VALUES
('What is economics?', '["The study of how individuals and societies allocate scarce resources", "The study of government laws", "The study of money and banking only", "The study of international trade only"]', 'A', 'Economics is the social science that studies how individuals, businesses, and governments make decisions to allocate scarce resources to satisfy unlimited wants and needs.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What is the basic economic problem?', '["Scarcity — unlimited wants vs. limited resources", "Unemployment", "Inflation", "Trade deficits"]', 'A', 'The basic economic problem is scarcity: human wants are unlimited while the resources to satisfy them are limited, requiring choices about allocation.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What is "opportunity cost"?', '["The value of the next best alternative forgone when making a choice", "The monetary price of a good", "The total cost of production", "The cost of labor"]', 'A', 'Opportunity cost is the value of the next best alternative given up when a choice is made. It is the hidden cost of any decision.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What happens to demand for a product when its price increases (all else equal)?', '["Demand decreases", "Demand increases", "Demand stays the same", "Demand doubles"]', 'A', 'According to the Law of Demand, when a product''s price increases (ceteris paribus), the quantity demanded decreases — there is an inverse relationship.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What happens to supply of a product when its price increases (all else equal)?', '["Supply increases", "Supply decreases", "Supply stays the same", "Supply becomes zero"]', 'A', 'According to the Law of Supply, when a product''s price increases (ceteris paribus), producers are willing to supply more of it — there is a direct relationship.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('At what point does the quantity supplied equal the quantity demanded?', '["Equilibrium", "Surplus", "Shortage", "Inflation"]', 'A', 'Market equilibrium is the point where quantity supplied equals quantity demanded, establishing the equilibrium price and quantity.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What is GDP (Gross Domestic Product)?', '["The total value of all goods and services produced in a country in a year", "The total government expenditure", "The total value of exports", "The total household income"]', 'A', 'GDP is the total monetary value of all finished goods and services produced within a country''s borders in a specific time period (usually one year).', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is inflation?', '["A sustained general increase in prices over time", "A decrease in the money supply", "An increase in employment", "A rise in government spending"]', 'A', 'Inflation is a sustained increase in the general price level of goods and services in an economy, resulting in decreased purchasing power of money.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What is deflation?', '["A sustained general decrease in price levels", "A rapid increase in prices", "A reduction in government debt", "An increase in exports"]', 'A', 'Deflation is a sustained decrease in the general price level of goods and services. While it may seem beneficial, it can lead to reduced spending and economic contraction.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is a "market economy"?', '["An economic system where prices are determined by supply and demand", "An economy controlled by the government", "An economy based on barter", "An economy with equal distribution of goods"]', 'A', 'A market economy (free market/capitalist economy) relies on supply and demand, price signals, and private ownership to determine production and distribution of goods.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is a "command economy"?', '["An economy where the government controls production and distribution", "An economy based on supply and demand", "A mixed economy", "An economy dominated by private corporations"]', 'A', 'A command economy (planned economy) is one where the government makes all major economic decisions about production, distribution, and prices. Example: former Soviet Union.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is "comparative advantage"?', '["The ability to produce a good at a lower opportunity cost than others", "Producing more of everything than others", "Having better technology than competitors", "Exporting more than importing"]', 'A', 'Comparative advantage is the ability of a country (or individual) to produce a good at a lower opportunity cost than others, forming the basis for beneficial trade.', 'Social Studies', 'Economics', 'hard', 'secondary'),
('What is the difference between a "need" and a "want" in economics?', '["Needs are essential for survival; wants are desires beyond basic needs", "Needs cost more than wants", "Wants are more important than needs", "They are the same in economics"]', 'A', 'Needs are essential goods/services required for survival (food, water, shelter). Wants are desires for goods/services beyond basic survival needs.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What are the four factors of production?', '["Land, labor, capital, and entrepreneurship", "Money, land, labor, and machines", "Goods, services, money, and labor", "Raw materials, workers, money, and management"]', 'A', 'The four factors of production are land (natural resources), labor (human effort), capital (machinery and equipment), and entrepreneurship (innovation and risk-taking).', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is "fiscal policy"?', '["Government decisions on spending and taxation to influence the economy", "Central bank decisions on interest rates", "Private sector investment decisions", "Trade agreements between countries"]', 'A', 'Fiscal policy refers to government use of taxation and spending to influence economic conditions. Expansionary fiscal policy increases spending/cuts taxes; contractionary does the opposite.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is "monetary policy"?', '["Central bank actions to control money supply and interest rates", "Government tax and spending decisions", "Trade policy", "Currency exchange regulations"]', 'A', 'Monetary policy is conducted by the central bank (Bangko Sentral ng Pilipinas in the Philippines) through controlling money supply, interest rates, and credit availability.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is a "surplus" in economics?', '["When quantity supplied exceeds quantity demanded at a given price", "When demand exceeds supply", "When the government spends more than it earns", "A positive trade balance"]', 'A', 'A market surplus occurs when quantity supplied exceeds quantity demanded at a given price. It puts downward pressure on prices until equilibrium is reached.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is a "shortage" in economics?', '["When quantity demanded exceeds quantity supplied at a given price", "When supply is too high", "When prices are too high", "When imports exceed exports"]', 'A', 'A shortage occurs when quantity demanded exceeds quantity supplied at a given price. It puts upward pressure on prices until equilibrium is reached.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is the Consumer Price Index (CPI)?', '["A measure of the average change in prices paid by consumers for goods and services", "The total output of the economy", "The interest rate set by banks", "The government''s tax revenue"]', 'A', 'The Consumer Price Index (CPI) tracks the weighted average price of a basket of consumer goods and services to measure inflation and changes in purchasing power.', 'Social Studies', 'Economics', 'hard', 'secondary'),
('What is "unemployment"?', '["The condition of able-bodied people who want to work but cannot find jobs", "People who choose not to work", "Part-time workers", "Workers on vacation"]', 'A', 'Unemployment refers to people who are able and willing to work but cannot find employment. The unemployment rate measures this as a percentage of the labor force.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What is "trade" in economics?', '["The voluntary exchange of goods and services between individuals or countries", "Government regulation of the market", "A company''s profit", "Natural resource extraction"]', 'A', 'Trade is the voluntary exchange of goods and services between parties. International trade allows countries to specialize based on comparative advantage.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What is a "tariff"?', '["A tax on imported goods", "A subsidy for exports", "A trade agreement", "A quota on production"]', 'A', 'A tariff is a tax imposed by a government on imported goods, making them more expensive to protect domestic industries from foreign competition.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What does "ceteris paribus" mean in economics?', '["All other things remaining equal or constant", "Supply equals demand", "Perfect competition", "Price is fixed"]', 'A', '"Ceteris paribus" (Latin: "other things equal") is an economic assumption that all other factors remain constant when analyzing the effect of one variable.', 'Social Studies', 'Economics', 'hard', 'secondary'),
('What is the Bangko Sentral ng Pilipinas (BSP)?', '["The central bank of the Philippines", "The national treasury of the Philippines", "A government bank for agriculture", "The Bureau of Internal Revenue"]', 'A', 'The Bangko Sentral ng Pilipinas (BSP) is the central bank of the Philippines, responsible for monetary policy, maintaining price stability, and supervising the financial system.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What is "monopoly"?', '["A market structure with one seller controlling the entire market", "A market with many sellers", "A government-owned company", "A cooperative business"]', 'A', 'A monopoly is a market structure where a single firm is the sole producer/seller of a product with no close substitutes, giving it significant market power.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is a "mixed economy"?', '["An economy with both private and government sectors making economic decisions", "An economy with only private businesses", "An economy with only government control", "An economy based on barter"]', 'A', 'A mixed economy combines elements of market and command economies — private enterprise operates freely in most sectors, while the government regulates and provides some goods/services.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is "GNP" (Gross National Product)?', '["The total value of goods and services produced by a country''s residents, regardless of location", "The total value produced within the borders only", "The total government spending", "The national savings rate"]', 'A', 'GNP measures the total value of goods and services produced by a country''s residents (both domestically and abroad), unlike GDP which only counts production within borders.', 'Social Studies', 'Economics', 'hard', 'secondary'),
('What is "economic growth"?', '["An increase in a country''s real GDP over time", "A decrease in unemployment", "An increase in exports", "A rise in consumer spending"]', 'A', 'Economic growth is typically measured as the percentage increase in real GDP (adjusted for inflation) over a period, indicating expanded productive capacity.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is "foreign direct investment" (FDI)?', '["Investment by a foreign entity in business operations in another country", "Government bonds sold to foreigners", "Loans from international banks", "Currency exchange between countries"]', 'A', 'FDI is an investment made by a company or individual in one country into business interests in another country, such as building factories or acquiring companies.', 'Social Studies', 'Economics', 'hard', 'secondary'),
('What does "supply and demand" determine in a market economy?', '["Prices and quantities of goods and services", "Government budget allocations", "Tax rates", "Wages of civil servants"]', 'A', 'In a market economy, the interaction of supply and demand determines the equilibrium price and quantity of goods and services traded.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What is "microeconomics"?', '["The study of individual consumers, firms, and markets", "The study of national economies", "The study of international trade", "The study of government finance"]', 'A', 'Microeconomics studies individual economic units (households, firms, markets) and their interactions, focusing on supply, demand, pricing, and resource allocation at the micro level.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is "macroeconomics"?', '["The study of the economy as a whole, including GDP, inflation, and unemployment", "The study of individual markets", "The study of consumer behavior", "The study of corporate strategy"]', 'A', 'Macroeconomics studies the economy as a whole, examining aggregate measures like GDP, national income, employment, inflation, and economic growth.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is a "public good"?', '["A good that is non-excludable and non-rival, like national defense", "Any good sold by the government", "A free good available to everyone", "A good subsidized by the government"]', 'A', 'A public good is non-excludable (cannot prevent access) and non-rival (one person''s use doesn''t reduce availability to others). Examples: national defense, lighthouses.', 'Social Studies', 'Economics', 'hard', 'secondary'),
('What is the "invisible hand" concept by Adam Smith?', '["Individuals pursuing self-interest unintentionally benefit society as a whole through market forces", "Government regulation that guides the economy", "The role of banks in directing investment", "Foreign investment in domestic markets"]', 'A', 'Adam Smith''s "invisible hand" metaphor describes how individuals pursuing their own self-interest in a free market unintentionally benefit society by creating efficient outcomes.', 'Social Studies', 'Economics', 'hard', 'secondary'),
('What is "subsidy"?', '["Government financial support given to businesses or consumers to lower prices", "A tax on imports", "A fine for illegal activities", "A government loan"]', 'A', 'A subsidy is a financial benefit (grant, tax reduction) provided by the government to individuals or businesses to reduce their costs and encourage production or consumption.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is "economic recession"?', '["A period of negative economic growth (declining GDP for at least two consecutive quarters)", "A period of high inflation", "A period of rapid economic growth", "A government budget deficit"]', 'A', 'A recession is typically defined as two consecutive quarters of negative GDP growth. It is characterized by reduced economic activity, rising unemployment, and falling consumer spending.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is "hyperinflation"?', '["Extremely rapid and out-of-control inflation", "Moderate inflation around 5%", "Deflation that spirals out of control", "Inflation caused by imports"]', 'A', 'Hyperinflation is an extremely high and typically accelerating inflation, often exceeding 50% per month, which devastates an economy (e.g., Zimbabwe 2008, Weimar Germany 1923).', 'Social Studies', 'Economics', 'hard', 'secondary'),
('What is the role of the Bureau of Internal Revenue (BIR) in the Philippines?', '["Collecting national internal revenue taxes", "Managing the national budget", "Overseeing the stock market", "Regulating banks"]', 'A', 'The Bureau of Internal Revenue (BIR) is the main tax-collecting agency of the Philippines, responsible for assessing and collecting all national internal revenue taxes.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is "trade deficit"?', '["When a country imports more than it exports", "When a country exports more than it imports", "When imports and exports are equal", "When a country bans imports"]', 'A', 'A trade deficit (negative trade balance) occurs when a country''s imports exceed its exports. The opposite is a trade surplus.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is "purchasing power"?', '["The amount of goods and services that money can buy", "The amount of money in circulation", "The interest rate on loans", "The foreign exchange rate"]', 'A', 'Purchasing power refers to the quantity of goods and services that a unit of currency can buy. Inflation reduces purchasing power over time.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What is the "poverty line"?', '["The minimum income level below which people are considered poor", "The average income in a country", "The maximum income for tax exemption", "The median household income"]', 'A', 'The poverty line (poverty threshold) is the minimum income level deemed necessary to meet basic needs. People earning below this level are considered to be living in poverty.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What is "Gini coefficient"?', '["A measure of income inequality within a country", "A measure of economic growth", "An inflation indicator", "A measure of trade balance"]', 'A', 'The Gini coefficient measures income inequality within a country, ranging from 0 (perfect equality) to 1 (maximum inequality). Higher values indicate greater inequality.', 'Social Studies', 'Economics', 'hard', 'secondary'),
('What is the main function of money?', '["Medium of exchange, store of value, and unit of account", "Generating profit only", "Government taxation tool", "Resource allocation only"]', 'A', 'Money serves three primary functions: (1) medium of exchange (used for transactions), (2) store of value (preserves wealth), and (3) unit of account (measuring worth).', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is "oligopoly"?', '["A market dominated by a few large sellers", "A market with one seller", "A market with many small sellers", "A government-controlled market"]', 'A', 'An oligopoly is a market structure dominated by a small number of large firms (e.g., smartphone market, airline industry) that have significant market power.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is "perfect competition"?', '["A market with many buyers and sellers, identical products, and free entry/exit", "A market with a few dominant firms", "A government-controlled market", "A market with a single seller"]', 'A', 'Perfect competition is a theoretical market structure with many buyers and sellers, homogeneous products, perfect information, and free entry/exit. No single buyer or seller can influence price.', 'Social Studies', 'Economics', 'hard', 'secondary'),
('What is "foreign exchange rate"?', '["The price at which one currency can be exchanged for another", "The interest rate on foreign loans", "The tariff rate on imports", "The inflation rate abroad"]', 'A', 'The foreign exchange rate is the rate at which one country''s currency can be exchanged for another''s. It is determined by supply and demand in the foreign exchange market.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What is the WTO (World Trade Organization)?', '["An international body that regulates and promotes global trade", "A bank for developing countries", "The United Nations'' economic agency", "A regional trade bloc"]', 'A', 'The World Trade Organization (WTO) is an international organization that deals with the rules of trade between nations, aiming to ensure smooth, free, and predictable international trade.', 'Social Studies', 'Economics', 'medium', 'secondary'),
('What does ASEAN stand for?', '["Association of Southeast Asian Nations", "Asian Special Economic Alliance Network", "Association of South and East Asian Nations", "Asian States Economic Action Network"]', 'A', 'ASEAN stands for Association of Southeast Asian Nations, a regional intergovernmental organization comprising 10 countries in Southeast Asia including the Philippines.', 'Social Studies', 'Economics', 'easy', 'secondary'),
('What is "Human Development Index" (HDI)?', '["A composite measure of life expectancy, education, and income per capita", "A measure of GDP growth rate", "An index of military strength", "A measure of trade balance"]', 'A', 'The Human Development Index (HDI) is a composite statistic that measures long-run human development through three dimensions: long and healthy life, knowledge, and decent standard of living.', 'Social Studies', 'Economics', 'hard', 'secondary'),
('What is "sustainable development"?', '["Development that meets present needs without compromising future generations'' ability to meet their needs", "Rapid economic growth at any cost", "Development focused only on industry", "Economic development with no environmental impact"]', 'A', 'Sustainable development (defined by the Brundtland Commission, 1987) meets the needs of the present without compromising the ability of future generations to meet their own needs.', 'Social Studies', 'Economics', 'medium', 'secondary');
